func (c *Client) Get(path string, params map[string]string) (json.RawMessage, error) {
	return c.GetWithHeaders(path, params, nil)
}

// cacheablePath reports whether a GET path may be served from the disk cache.
// Account-state reads (/portfolio/*) are NEVER cached: they're used to verify
// fills/positions minutes after the user trades in the browser, and a 5-minute
// stale answer labeled "live" reads exactly like "the order didn't fill"
// (audit 2026-06-09). External trades can't invalidate this CLI's cache, so
// exemption — not TTL tuning — is the only safe policy for those paths.
func cacheablePath(path string) bool {
	return !strings.HasPrefix(path, "/portfolio")
}

func (c *Client) GetWithHeaders(path string, params map[string]string, headers map[string]string) (json.RawMessage, error) {
	cacheable := !c.NoCache && !c.DryRun && c.cacheDir != "" && cacheablePath(path)
	if cacheable {
		if cached, ok := c.readCache(path, params); ok {
			return cached, nil
		}
	}
	result, _, err := c.do("GET", path, params, nil, headers)
	if err == nil && cacheable {
		c.writeCache(path, params, result)
	}
	return result, err
}

func (c *Client) ProbeGet(path string) (int, error) {
	_, status, err := c.do("GET", path, nil, nil, nil)
	return status, err
}

func (c *Client) cacheKey(path string, params map[string]string) string {
	// Sorted keys + explicit separators: Go map iteration is randomized, so
	// the old concatenation produced a DIFFERENT key for the same request on
	// different runs (cache misses), and "a=1&b=2" vs "a=1b" could collide
	// (audit 2026-06-09).
	keys := make([]string, 0, len(params))
	for k := range params {
		keys = append(keys, k)
	}
	sort.Strings(keys)
	var b strings.Builder
	b.WriteString(path)
	for _, k := range keys {
		b.WriteString("\x00")
		b.WriteString(k)
		b.WriteString("=")
		b.WriteString(params[k])
	}
	h := sha256.Sum256([]byte(b.String()))
	return hex.EncodeToString(h[:8])
}

func (c *Client) readCache(path string, params map[string]string) (json.RawMessage, bool) {
	cacheFile := filepath.Join(c.cacheDir, c.cacheKey(path, params)+".json")
	info, err := os.Stat(cacheFile)
	if err != nil || time.Since(info.ModTime()) > 5*time.Minute {
		return nil, false
	}
	data, err := os.ReadFile(cacheFile)
	if err != nil {
		return nil, false
	}
	return json.RawMessage(data), true
}

func (c *Client) writeCache(path string, params map[string]string, data json.RawMessage) {
	// 0700/0600: cached responses can carry account data — keep them
	// owner-only (audit 2026-06-09).
	os.MkdirAll(c.cacheDir, 0o700)
	cacheFile := filepath.Join(c.cacheDir, c.cacheKey(path, params)+".json")
	os.WriteFile(cacheFile, []byte(data), 0o600)
}

// invalidateCache wholesale-removes the cache directory after a successful
// non-GET request. Best-effort — ignores RemoveAll error per the design
// pattern at https://github.com/mvanhorn/cli-printing-press/blob/main/docs/solutions/design-patterns/http-client-cache-invalidate-on-mutation-2026-05-05.md
func (c *Client) invalidateCache() {
	if c.cacheDir == "" {
		return
	}
	_ = os.RemoveAll(c.cacheDir)
}

